#!/usr/bin/env pwshDescribe 'Pre-Close Validator Integration Tests' {    BeforeAll {        $script:root = $PSScriptRoot | Split-Path -Parent | Split-Path -Parent        $script:validator = Join-Path $script:root 'scripts\utilities\pre-close-validator.ps1'        $script:tempRoot = Join-Path $script:root 'tmp-pre-close-validator-integration-tests'        $script:originalGentleVanguardBaseDir = $env:GENTLE_VANGUARD_BASE_DIR        $script:startingLocation = (Get-Location).Path    }    BeforeEach {        if (Test-Path $script:tempRoot) {            Set-Location $script:startingLocation            Remove-Item -Path $script:tempRoot -Recurse -Force -ErrorAction SilentlyContinue        }        New-Item -ItemType Directory -Path $script:tempRoot -Force | Out-Null    }    AfterEach {        Set-Location $script:startingLocation        if ($null -eq $script:originalGentleVanguardBaseDir) {            Remove-Item Env:GENTLE_VANGUARD_BASE_DIR -ErrorAction SilentlyContinue        } else {            $env:GENTLE_VANGUARD_BASE_DIR = $script:originalGentleVanguardBaseDir        }        if (Test-Path $script:tempRoot) {            Remove-Item -Path $script:tempRoot -Recurse -Force -ErrorAction SilentlyContinue        }        $global:LASTEXITCODE = 0    }    function Initialize-TestRepo {        param(            [string]$Name,            [switch]$WithUpstream        )        $repoPath = Join-Path $script:tempRoot $Name        New-Item -ItemType Directory -Path (Join-Path $repoPath 'config') -Force | Out-Null        '{}' | Set-Content -Path (Join-Path $repoPath 'config\placeholder.json') -Encoding UTF8        Push-Location $repoPath        try {            git init | Out-Null            git config user.email 'tests@gentle-vanguard.local'            git config user.name 'Gentle-Vanguard Tests'            git branch -M main | Out-Null            git add . | Out-Null            git commit -m 'test: seed repo' | Out-Null            if ($WithUpstream) {                $remotePath = Join-Path $script:tempRoot "$Name-remote.git"                git init --bare $remotePath | Out-Null                git remote add origin $remotePath                git push -u origin main | Out-Null            }        }        finally {            Pop-Location        }        return $repoPath    }    function Invoke-Validator {        param(            [string]$RepoPath,            [switch]$AutoResolve,            [switch]$Force        )        $env:GENTLE_VANGUARD_BASE_DIR = $RepoPath        Set-Location $script:startingLocation        try {            if ($AutoResolve -and $Force) {                return (& $script:validator -AutoResolve -Force -NoExit 2>&1)            }            if ($AutoResolve) {                return (& $script:validator -AutoResolve -NoExit 2>&1)            }            if ($Force) {                return (& $script:validator -Force -NoExit 2>&1)            }            return (& $script:validator -NoExit 2>&1)        }        finally {            Set-Location $script:startingLocation        }    }    It 'passes on a clean repo when Force allows missing upstream' {        $repoPath = Initialize-TestRepo -Name 'clean-force'        $output = Invoke-Validator -RepoPath $repoPath -Force        $output[-1] | Should -Be 0    }    It 'fails on a clean repo without upstream when Force is not used' {        $repoPath = Initialize-TestRepo -Name 'no-upstream-blocking'        $output = Invoke-Validator -RepoPath $repoPath        $output[-1] | Should -Be 1    }    It 'fails when uncommitted changes exist and AutoResolve is not used' {        $repoPath = Initialize-TestRepo -Name 'uncommitted-blocking'        'pending' | Set-Content -Path (Join-Path $repoPath 'pending.txt') -Encoding UTF8        $output = Invoke-Validator -RepoPath $repoPath -Force        $output[-1] | Should -Be 1        Push-Location $repoPath        try {            (git status --short | Out-String) | Should -Match 'pending.txt'        }        finally {            Pop-Location        }    }    It 'auto-commits pending changes when AutoResolve is enabled' {        $repoPath = Initialize-TestRepo -Name 'auto-commit'        'pending' | Set-Content -Path (Join-Path $repoPath 'pending.txt') -Encoding UTF8        $output = Invoke-Validator -RepoPath $repoPath -AutoResolve -Force        $output[-1] | Should -Be 0        Push-Location $repoPath        try {            [string]::IsNullOrWhiteSpace((git status --short | Out-String)) | Should -Be $true            (git log --oneline -1 | Out-String) | Should -Match 'auto-commit before session close'        }        finally {            Pop-Location        }    }    It 'removes session lock files when AutoResolve is enabled' {        $repoPath = Initialize-TestRepo -Name 'lock-cleanup'        New-Item -ItemType Directory -Path (Join-Path $repoPath '.session') -Force | Out-Null        'lock' | Set-Content -Path (Join-Path $repoPath '.session\session.lock') -Encoding UTF8        $output = Invoke-Validator -RepoPath $repoPath -AutoResolve -Force        $output[-1] | Should -Be 0        Test-Path (Join-Path $repoPath '.session\session.lock') | Should -Be $false    }    It 'fails when session lock files exist and AutoResolve is not used' {        $repoPath = Initialize-TestRepo -Name 'lock-blocking' -WithUpstream        New-Item -ItemType Directory -Path (Join-Path $repoPath '.session') -Force | Out-Null        'lock' | Set-Content -Path (Join-Path $repoPath '.session\session.lock') -Encoding UTF8        Push-Location $repoPath        try {            git add . | Out-Null            git commit -m 'test: add session lock' | Out-Null            git push origin main | Out-Null        }        finally {            Pop-Location        }        $output = Invoke-Validator -RepoPath $repoPath -Force        $output[-1] | Should -Be 1    }    It 'passes when repo is already synced with upstream' {        $repoPath = Initialize-TestRepo -Name 'upstream-synced' -WithUpstream        $output = Invoke-Validator -RepoPath $repoPath -Force        $output[-1] | Should -Be 0    }    It 'fails when unpushed commits exist and AutoResolve is not used' {        $repoPath = Initialize-TestRepo -Name 'unpushed-blocking' -WithUpstream        'unpushed' | Set-Content -Path (Join-Path $repoPath 'unpushed.txt') -Encoding UTF8        Push-Location $repoPath        try {            git add . | Out-Null            git commit -m 'test: unpushed local change' | Out-Null        }        finally {            Pop-Location        }        $output = Invoke-Validator -RepoPath $repoPath -Force        $output[-1] | Should -Be 1    }    It 'auto-pushes local commits to upstream when AutoResolve is enabled' {        $repoPath = Initialize-TestRepo -Name 'auto-push' -WithUpstream        'unpushed' | Set-Content -Path (Join-Path $repoPath 'unpushed.txt') -Encoding UTF8        Push-Location $repoPath        try {            git add . | Out-Null            git commit -m 'test: local unpushed change' | Out-Null        }        finally {            Pop-Location        }        $output = Invoke-Validator -RepoPath $repoPath -AutoResolve -Force        $output[-1] | Should -Be 0        Push-Location $repoPath        try {            [int](git rev-list --count '@{upstream}..HEAD') | Should -Be 0        }        finally {            Pop-Location        }    }    It 'fails when auto-push is requested but the configured remote is unavailable' {        $repoPath = Initialize-TestRepo -Name 'push-failure' -WithUpstream        'unpushed' | Set-Content -Path (Join-Path $repoPath 'unpushed.txt') -Encoding UTF8        Push-Location $repoPath        try {            git add . | Out-Null            git commit -m 'test: local change before remote failure' | Out-Null        }        finally {            Pop-Location        }        $remotePath = Join-Path $script:tempRoot 'push-failure-remote.git'        $remoteOfflinePath = Join-Path $script:tempRoot 'push-failure-remote.offline'        Move-Item -Path $remotePath -Destination $remoteOfflinePath        $output = Invoke-Validator -RepoPath $repoPath -AutoResolve -Force        $output[-1] | Should -Be 1    }}


